  ('heelevel3-29a002de-moex-00025', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-114-916530c6', 'sub-heelevel3-29a002de-01', NULL, 'single_choice', '甲教唆乙行竊，乙萌生犯意，但隨即因車禍住院，甲應如何論處？', '["成立教唆竊盜既遂", "成立教唆竊盜未遂", "成立教唆預備竊盜", "不成立犯罪"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "11be7e46a91d", "answer_pdf_sha1": "2951af1e823c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "227", "s": "0913", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00026', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-114-916530c6', 'sub-heelevel3-29a002de-01', NULL, 'single_choice', '甲埋伏於路邊欲殺乙，見乙、丙二人並肩而行，舉槍瞄準，儘管知道自己無法排除誤中丙的可能性， 但因機不可失，還是決定賭一把。扣下扳機擊發後，子彈未打中乙，卻將丙擊斃。甲應如何論罪？', '["成立殺人既遂罪與殺人未遂罪，二者依想像競合之例處斷", "成立殺人未遂罪與過失致人於死罪，二者依想像競合之例處斷", "成立殺人未遂罪與過失致人於死罪，二者依實質競合之例處斷", "成立殺人未遂罪與過失致人於死罪，二者依法條競合之例處斷"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "11be7e46a91d", "answer_pdf_sha1": "2951af1e823c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "227", "s": "0913", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00027', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-114-916530c6', 'sub-heelevel3-29a002de-01', NULL, 'single_choice', '行為後，填補相關空白刑法的法規命令有所變更，依照實務見解應如何處理？', '["此屬法律變更，應適用刑法第2條第1項本文（從舊原則）處理", "此屬法律變更，應適用刑法第2條第1項但書（從輕原則）處理", "此屬事實變更，無刑法第2條第1項之適用", "此屬事實變更，應適用刑法第2條第1項本文（從舊原則）處理"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "11be7e46a91d", "answer_pdf_sha1": "2951af1e823c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "227", "s": "0913", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00028', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-114-e733516d', 'sub-heelevel3-29a002de-02', NULL, 'essay', '甲向管轄法院起訴乙，請求判決命被告乙將 P油畫返還予原告甲，其主
張乙從甲取得P油畫所有權無法律上原因，依不當得利規定請求乙返還。
甲因於第一審遭以無理由判決駁回，提起第二審上訴。甲、乙於第二審
合意停止訴訟程序後，經過半年未續行訴訟，而就雙方權利爭執也一直
未能達成協議。甲於合意停止後七個月，又向乙的住所地 C地方法院起
訴乙，請求返還不當得利 P油畫所有權。對於甲的此次起訴，C法院應
如何裁判？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "b919d2e5a3b5", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "227", "s": "0911", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民事訴訟法與刑事訴訟法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00029', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-114-e733516d', 'sub-heelevel3-29a002de-02', NULL, 'essay', '甲起訴乙請求清償借款新臺幣（以下同）500萬元（A債權），乙主張該
筆借款已經清償；就清償事實，甲否認，乙未能充分證明。甲於第一審
獲全部勝訴判決，乙提起第二審上訴。於第二審程序中，上訴人乙除補
充已清償系爭借款的事實及證據外，並主張自己對甲有一筆剛到期的
800 萬元貨款債權（B債權），聲明預備抵銷，並對甲提起反訴，請求給
付抵銷剩餘的貨款 300萬元。乙所提的反訴是否合法？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:38+00:00", "source_pdf_sha1": "b919d2e5a3b5", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "227", "s": "0911", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民事訴訟法與刑事訴訟法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "司法行政"}'::jsonb, NULL),
  ('heelevel3-29a002de-moex-00030', 'heelevel3-29a002de', 'heelevel3-29a002de-moex-114-e733516d', 'sub-heelevel3-29a002de-02', NULL, 'essay', '甲、乙因為細故起了爭執，二人互毆，甲因而受有輕傷。甲忿而向司法
警察官提出告訴。檢察官偵查完畢後，向法院提起公訴。於審判中，乙
方知情況不妙，遂向甲表示道歉。甲向法院表示願意撤回告訴。數日後，
